# ------------------------------------------------------------------
# Graph nodes
# ------------------------------------------------------------------
def _nodes() -> list:
    return [
        helper.make_node('MatMul', inputs=['model_input', 'n0_mm4d_w'], outputs=['n0_mm4d_out']),
        helper.make_node('Mul', inputs=['n0_mm4d_out', 'n100_mar_scale'], outputs=['n100_mar_mul']),
        helper.make_node('Add', inputs=['n100_mar_mul', 'n100_mar_bias'], outputs=['n100_mar_add']),
        helper.make_node('Relu', inputs=['n100_mar_add'], outputs=['n100_mar_out']),
        helper.make_node('ConvTranspose', inputs=['n100_mar_out', 'n200_ctbnr_w', 'n200_ctbnr_b'], outputs=['n200_ctbnr_ct'], kernel_shape=[2, 2], strides=[2, 2]),
        helper.make_node('BatchNormalization', inputs=['n200_ctbnr_ct', 'n200_ctbnr_bn_scale', 'n200_ctbnr_bn_bias', 'n200_ctbnr_bn_mean', 'n200_ctbnr_bn_var'], outputs=['n200_ctbnr_bn'], epsilon=9.999999747378752e-06),
        helper.make_node('Relu', inputs=['n200_ctbnr_bn'], outputs=['n200_ctbnr_out']),
        helper.make_node('Conv', inputs=['n200_ctbnr_out', 'n300_cap_w', 'n300_cap_b'], outputs=['n300_cap_out'], kernel_shape=[3, 3], pads=[0, 1, 0, 1], strides=[1, 1]),
        helper.make_node('Pad', inputs=['n300_cap_out', 'n400_rfpcv_pads'], outputs=['n400_rfpcv_pad'], mode='reflect'),
        helper.make_node('Conv', inputs=['n400_rfpcv_pad', 'n400_rfpcv_w', 'n400_rfpcv_b'], outputs=['n400_rfpcv_out'], kernel_shape=[3, 3], pads=[0, 0, 0, 0], strides=[1, 1]),
    ]

# ------------------------------------------------------------------
# Model builder
# ------------------------------------------------------------------
def build_model() -> bytes:
    inputs_info  = [helper.make_tensor_value_info(INPUT_NAME, TensorProto.FLOAT, INPUT_SHAPE)]
    outputs_info = [helper.make_tensor_value_info(OUTPUT_NAME, TensorProto.FLOAT, OUTPUT_SHAPE)]
    graph = helper.make_graph(_nodes(), "bug_000170", inputs_info, outputs_info, initializer=_inits())
    model = helper.make_model(graph, opset_imports=[helper.make_opsetid("", OPSET)])
    model.ir_version = IR_VERSION
    return model.SerializeToString()


